import { useEffect, useRef } from 'react';
import ArvoCheckbox from '../Checkbox/Checkbox';
import ArvoRadio from '../Radio/Radio';
import ArvoIconButton from '../IconButton/IconButton';
import type { HybridPopoverItem } from './HybridPopover';

export type FilterOptionSelectionKind = 'multi' | 'single' | 'none';

export interface FilterOptionProps {
  item: HybridPopoverItem;
  selection: FilterOptionSelectionKind;
  isChecked: boolean;
  isDisabled?: boolean;
  /** Whether at least one item in the list has a drag handle (so a spacer aligns rows). */
  hasAnyDragHandle: boolean;
  /** Whether reorder is enabled and this row should render its drag handle. */
  isDraggable: boolean;
  /** Group id this option belongs to, exposed via data-group for the DnD adapter. */
  groupId: string | null;
  /** Shared name for radios in single mode (typically the panel id). */
  radioName?: string;
  onToggle: (item: HybridPopoverItem) => void;
  onInline?: (item: HybridPopoverItem) => void;
}

export function FilterOption({
  item,
  selection,
  isChecked,
  isDisabled,
  hasAnyDragHandle,
  isDraggable,
  groupId,
  radioName,
  onToggle,
  onInline,
}: FilterOptionProps) {
  const itemDisabled = isDisabled || item.isDisabled;
  const showCheckSlot = selection !== 'none';
  const showExclude = selection === 'multi' && !!item.isExcluded;
  const showInline = !!item.hasInline;

  const checkSlotRef = useRef<HTMLSpanElement | null>(null);

  // The row owns the single Tab stop (managed by createTabRoving on the
  // parent __list). The native checkbox/radio __input must therefore be
  // taken out of the tab order — Space/Enter on the row delegates the
  // toggle. Pointer activation on the input itself still fires onChange.
  useEffect(() => {
    const slot = checkSlotRef.current;
    if (!slot) return;
    slot
      .querySelectorAll<HTMLInputElement>(
        '.arvo-checkbox__input, .arvo-radio__input',
      )
      .forEach((input) => {
        input.tabIndex = -1;
      });
  });

  // Row role tracks the parent list container's role: `option` lives
  // under `listbox`; when selectionMode='none' the list container is
  // `group`, so each row is a plain `listitem` (aria-selected omitted).
  const rowRole = selection === 'none' ? 'listitem' : 'option';

  return (
    <div
      className="arvo-hpop__opt"
      role={rowRole}
      tabIndex={-1}
      aria-selected={
        rowRole === 'option' && showCheckSlot ? isChecked : undefined
      }
      aria-disabled={itemDisabled || undefined}
      data-id={item.id}
      data-group={groupId ?? undefined}
      onKeyDown={(event) => {
        if (event.key !== ' ' && event.key !== 'Enter') return;
        if (itemDisabled) return;
        if (selection === 'none') return;
        // Don't intercept when focus is inside an interactive child (e.g.
        // the inline chevron button) so its own activation runs first.
        const target = event.target as HTMLElement;
        if (target !== event.currentTarget) {
          const interactive = target.closest('button, a, [role="button"]');
          if (interactive && interactive !== event.currentTarget) return;
        }
        event.preventDefault();
        onToggle(item);
      }}
    >
      {isDraggable ? (
        <span
          className="arvo-hpop__opt__drag"
          role="button"
          tabIndex={-1}
          aria-roledescription="sortable"
          aria-keyshortcuts="Control+ArrowUp Control+ArrowDown"
          aria-label={`Drag ${item.label}`}
          aria-disabled={itemDisabled || undefined}
        >
          <i className="o9con o9con-drag-handle" aria-hidden="true" />
        </span>
      ) : hasAnyDragHandle ? (
        <span className="arvo-hpop__opt__spacer" aria-hidden="true" />
      ) : null}

      {showCheckSlot && (
        <span ref={checkSlotRef} className="arvo-hpop__opt__check">
          {selection === 'multi' ? (
            <ArvoCheckbox
              size="sm"
              isChecked={isChecked}
              isIndeterminate={item.isIndeterminate}
              isExcluded={item.isExcluded}
              isDisabled={itemDisabled}
              value={item.id}
              aria-label={item.label}
              onChange={() => onToggle(item)}
            />
          ) : (
            <ArvoRadio
              size="sm"
              name={radioName}
              value={item.id}
              isChecked={isChecked}
              isDisabled={itemDisabled}
              aria-label={item.label}
              onChange={() => onToggle(item)}
            />
          )}
        </span>
      )}

      <span
        className="arvo-hpop__opt__lbl"
        onClick={() => {
          if (itemDisabled) return;
          if (selection === 'none') return;
          onToggle(item);
        }}
      >
        {item.label}
        {item.secondaryLabel && (
          <span className="arvo-hpop__opt__secondary">{item.secondaryLabel}</span>
        )}
      </span>

      {showExclude && (
        <span
          className="arvo-hpop__opt__exclude o9con o9con-exclude"
          aria-label="Excluded"
          role="img"
        />
      )}

      {showInline && (
        <span className="arvo-hpop__opt__chev">
          <ArvoIconButton
            icon="angle-right"
            variant="tertiary"
            size="sm"
            tooltip={`Open ${item.label}`}
            isDisabled={itemDisabled}
            onClick={(e) => {
              e.stopPropagation();
              onInline?.(item);
            }}
          />
        </span>
      )}
    </div>
  );
}

export default FilterOption;
